@app.route("/validate_code", methods=["POST"])
def validate_code():
    code = request.form.get("code", "") or (request.json or {}).get("code", "")
    user_id = auth_codes.get(code)

    if not user_id:
        return jsonify({"valid": False}), 404

    return jsonify({
        "valid": True,
        "code": code,
        "user_id": user_id,
    })


@app.route("/introspect", methods=["POST"])
def introspect():
    token = request.form.get("token", "") or (request.json or {}).get("token", "")
    user_id = access_tokens.get(token)

    if not user_id:
        return jsonify({"active": False})

    return jsonify({
        "active": True,
        "user_id": user_id,
        "token_type": "Bearer",
    })


